// src/data/skillPrereqGraph.ts
//
// Machine-readable prerequisite dependency graph extracted from skill-phase-d.json.
//
// Source: `skill_prerequisites` prose for each skill. Only explicit skill ID
// references (pattern [A-Z]{2,3}-\d{2}) are captured — skills without
// named prerequisites have an empty array.
//
// Generated by: reading skill-phase-d.json and regex-extracting all `[A-Z]{2,3}-\d{2}`
// tokens from each skill's `skill_prerequisites` field, excluding self-references.

